import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Layout from '../components/4_unity/Layout';
import Header from '../components/3_organism/Header';
import FooterSection from '../components/3_organism/FooterSection';
import SectionTitle from '../components/1_atoms/SectionTitle';
import { useAuth } from '../hooks/useAuth';
import apiClient from '../api/apiClient';

function AccountPage() {
  const { user, logout, isAuthenticated } = useAuth();
  const navigate = useNavigate();
  const [characters, setCharacters] = useState([]);
  const [selectedCharacter, setSelectedCharacter] = useState(null);
  const [background, setBackground] = useState(null);
  const [sessionGameID, setSessionGameID] = useState(null);
  const [difficulty, setDifficulty] = useState('EASY');
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);
  const [gameStarted, setGameStarted] = useState(false);

  useEffect(() => {
    if (!isAuthenticated) {
      navigate('/login');
    }
  }, [isAuthenticated, navigate]);

  useEffect(() => {
    setCharacters([
      { id: 1, fullName: 'Сохранитель' },
      { id: 2, fullName: 'Страховщик' },
      { id: 3, fullName: 'Инвестор' },
    ]);
  }, []);

  const handleCharacterSelect = async (character) => {
    setSelectedCharacter(character);
    setError(null);
    setLoading(true);

    try {
      const sessionResponse = await apiClient.post('/v1/session_game', {
        fullName: character.fullName,
      });

      const newSessionGameID = sessionResponse.id || sessionResponse.sessionGameID;
      setSessionGameID(newSessionGameID);

      const backgroundResponse = await apiClient.get(
        `/v1/background/${difficulty}/${newSessionGameID}`
      );

      setBackground(backgroundResponse);
      setGameStarted(true);
    } catch (err) {
      setError(err.message || 'Failed to start game');
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  if (!isAuthenticated) {
    return null;
  }

  return (
    <Layout>
      <Header />
      <main className="account-page">
        <section className="account-hero">
          <div className="account-hero__top">
            <h1>{user?.name} {user?.surname}</h1>
            <button className="button button--primary" onClick={handleLogout}>
              Выход
            </button>
          </div>

          {!gameStarted ? (
            <>
              <div className="account-hero__title">
                <h2>Выбери своего персонажа</h2>
              </div>

              {error && <div className="auth-error" style={{ marginBottom: '20px' }}>{error}</div>}

              <div className="characters-list">
                {characters.map((character) => (
                  <button
                    key={character.id}
                    type="button"
                    className={`character-card ${
                      selectedCharacter?.id === character.id ? 'character-card--active' : ''
                    }`}
                    onClick={() => handleCharacterSelect(character)}
                    disabled={loading}
                  >
                    <div className="character-card__info">
                      <span className="character-card__name">{character.fullName}</span>
                    </div>
                    {loading && selectedCharacter?.id === character.id && (
                      <div className="character-card__loading">Загрузка...</div>
                    )}
                  </button>
                ))}
              </div>
            </>
          ) : (
            <div className="game-session">
              <div className="account-hero__title">
                <h2>{selectedCharacter?.fullName}</h2>
              </div>

              {background && (
                <div className="game-background">
                  <h3>Предыстория персонажа</h3>
                  <div className="background-content">
                    <p>{background.background}</p>
                  </div>
                  {background.status && (
                    <div className="character-stats">
                      <div className="stat-item">
                        <span>Возраст:</span>
                        <strong>{background.status.age}</strong>
                      </div>
                      <div className="stat-item">
                        <span>Деньги:</span>
                        <strong>${background.status.money}</strong>
                      </div>
                      <div className="stat-item">
                        <span>Здоровье:</span>
                        <strong>{background.status.health}%</strong>
                      </div>
                      <div className="stat-item">
                        <span>Счастье:</span>
                        <strong>{background.status.happiness}%</strong>
                      </div>
                      <div className="stat-item">
                        <span>Годовые сбережения:</span>
                        <strong>${background.status.annualSavings}</strong>
                      </div>
                    </div>
                  )}
                </div>
              )}

              <button
                className="button button--secondary"
                onClick={() => {
                  setGameStarted(false);
                  setSelectedCharacter(null);
                  setBackground(null);
                  setSessionGameID(null);
                }}
              >
                Выбрать другого персонажа
              </button>
            </div>
          )}
        </section>
      </main>
      <FooterSection />
    </Layout>
  );
}

export default AccountPage;
